 21→func TestUploadHandler_NilStorage(t *testing.T) {
 22→	handler := uploadHandler(nil, 50<<20)
 23→
 24→	req := httptest.NewRequest(http.MethodPost, "/upload", nil)
 25→	ctx := auth.WithClaims(req.Context(), &auth.Claims{UserID: uuid.New()})
 26→	req = req.WithContext(ctx)
 27→
 28→	rr := httptest.NewRecorder()
 29→	handler.ServeHTTP(rr, req)
 30→
 31→	if rr.Code != http.StatusServiceUnavailable {
 32→		t.Errorf("expected 503, got %d", rr.Code)
 33→	}
 34→}
