 78→func TestAllowedAudioTypes(t *testing.T) {
 79→	expected := map[string]string{
 80→		"audio/mpeg":  "mp3",
 81→		"audio/wav":   "wav",
 82→		"audio/x-wav": "wav",
 83→		"audio/ogg":   "ogg",
 84→		"audio/webm":  "webm",
 85→		"audio/mp4":   "m4a",
 86→		"audio/x-m4a": "m4a",
 87→		"audio/flac":  "flac",
 88→	}
 89→
 90→	for mime, ext := range expected {
 91→		got, ok := allowedAudioTypes[mime]
 92→		if !ok {
 93→			t.Errorf("expected %q in allowedAudioTypes", mime)
 94→			continue
 95→		}
 96→		if got != ext {
 97→			t.Errorf("allowedAudioTypes[%q] = %q, want %q", mime, got, ext)
 98→		}
 99→	}
100→
101→	// Verify non-audio types are not allowed
102→	disallowed := []string{"text/plain", "image/png", "video/mp4", "application/pdf"}
103→	for _, mime := range disallowed {
104→		if _, ok := allowedAudioTypes[mime]; ok {
105→			t.Errorf("unexpected type %q in allowedAudioTypes", mime)
106→		}
107→	}
108→}
