140→func TestSniffAudioType_ValidFormats(t *testing.T) {
141→	tests := []struct {
142→		name string
143→		buf  []byte
144→		want string
145→	}{
146→		{
147→			name: "MP3 ID3v2 tag",
148→			buf:  append([]byte("ID3"), make([]byte, 20)...),
149→			want: "audio/mpeg",
150→		},
151→		{
152→			name: "MP3 frame sync 0xFFFB",
153→			buf:  append([]byte{0xFF, 0xFB, 0x90, 0x00}, make([]byte, 20)...),
154→			want: "audio/mpeg",
155→		},
156→		{
157→			name: "MP3 frame sync 0xFFF3",
158→			buf:  append([]byte{0xFF, 0xF3, 0x90, 0x00}, make([]byte, 20)...),
159→			want: "audio/mpeg",
160→		},
161→		{
162→			// 0xFFE2 = sync(111) + version 00(v2.5) + layer 01(L3) — valid
163→			name: "MP3 frame sync MPEG2.5 Layer3",
164→			buf:  append([]byte{0xFF, 0xE2, 0x00, 0x00}, make([]byte, 20)...),
165→			want: "audio/mpeg",
166→		},
167→		{
168→			name: "WAV RIFF/WAVE",
169→			buf: func() []byte {
170→				b := make([]byte, 44)
171→				copy(b[0:4], "RIFF")
172→				copy(b[8:12], "WAVE")
173→				return b
174→			}(),
175→			want: "audio/wav",
176→		},
177→		{
178→			name: "OGG",
179→			buf:  append([]byte("OggS"), make([]byte, 20)...),
180→			want: "audio/ogg",
181→		},
182→		{
183→			name: "FLAC",
184→			buf:  append([]byte("fLaC"), make([]byte, 20)...),
185→			want: "audio/flac",
186→		},
187→		{
188→			name: "WebM EBML header",
189→			buf:  append([]byte{0x1A, 0x45, 0xDF, 0xA3}, make([]byte, 20)...),
190→			want: "audio/webm",
191→		},
192→		{
193→			name: "M4A/MP4 ftyp",
194→			buf: func() []byte {
195→				b := make([]byte, 24)
196→				// Size (4 bytes) + "ftyp" + brand
197→				b[0], b[1], b[2], b[3] = 0x00, 0x00, 0x00, 0x20
198→				copy(b[4:8], "ftyp")
199→				copy(b[8:12], "M4A ")
200→				return b
201→			}(),
202→			want: "audio/mp4",
203→		},
204→		{
205→			name: "MP4 ftyp isom",
206→			buf: func() []byte {
207→				b := make([]byte, 24)
208→				b[0], b[1], b[2], b[3] = 0x00, 0x00, 0x00, 0x1C
209→				copy(b[4:8], "ftyp")
210→				copy(b[8:12], "isom")
211→				return b
212→			}(),
213→			want: "audio/mp4",
214→		},
215→	}
216→
217→	for _, tt := range tests {
218→		t.Run(tt.name, func(t *testing.T) {
219→			got := sniffAudioType(tt.buf)
220→			if got != tt.want {
221→				t.Errorf("sniffAudioType() = %q, want %q", got, tt.want)
222→			}
223→		})
224→	}
225→}
