 11→
 12→const testSecret = "test-secret-key-for-hmac-validation"
 13→
 14→func makeHMACToken(t *testing.T, secret string, claims Claims) string {
 15→	t.Helper()
 16→	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
 17→	signed, err := token.SignedString([]byte(secret))
 18→	if err != nil {
 19→		t.Fatalf("failed to sign token: %v", err)
 20→	}
 21→	return signed
 22→}
 23→
 24→func TestHMACValidator_ValidToken(t *testing.T) {
 25→	uid := uuid.New()
 26→	tokenStr := makeHMACToken(t, testSecret, Claims{
 27→		RegisteredClaims: jwt.RegisteredClaims{
 28→			Subject:   uid.String(),
 29→			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
 30→		},
 31→		UserID:     uid,
 32→		Email:      "test@example.com",
 33→		ClientType: "web",
 34→	})
 35→
 36→	v := NewHMACValidator(testSecret)
 37→	claims, err := v.Validate(tokenStr)
 38→	if err != nil {
 39→		t.Fatalf("unexpected error: %v", err)
 40→	}
 41→	if claims.UserID != uid {
 42→		t.Errorf("UserID = %v, want %v", claims.UserID, uid)
 43→	}
 44→	if claims.Email != "test@example.com" {
 45→		t.Errorf("Email = %q, want %q", claims.Email, "test@example.com")
 46→	}
 47→	if claims.ClientType != "web" {
 48→		t.Errorf("ClientType = %q, want %q", claims.ClientType, "web")
 49→	}
 50→}
 51→
 52→func TestHMACValidator_ExpiredToken(t *testing.T) {
 53→	tokenStr := makeHMACToken(t, testSecret, Claims{
 54→		RegisteredClaims: jwt.RegisteredClaims{
 55→			ExpiresAt: jwt.NewNumericDate(time.Now().Add(-time.Hour)),
 56→		},
 57→	})
 58→
 59→	v := NewHMACValidator(testSecret)
 60→	_, err := v.Validate(tokenStr)
 61→	if err == nil {
 62→		t.Fatal("expected error for expired token")
 63→	}
 64→}
