 24→func TestRequestID_GeneratesID(t *testing.T) {
 25→	handler := RequestID(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
 26→		id := requestIDFromContext(r.Context())
 27→		if id == "" {
 28→			t.Error("request ID not in context")
 29→		}
 30→		w.WriteHeader(http.StatusOK)
 31→	}))
 32→
 33→	rr := httptest.NewRecorder()
 34→	handler.ServeHTTP(rr, httptest.NewRequest("GET", "/", nil))
 35→
 36→	if rr.Header().Get("X-Request-ID") == "" {
 37→		t.Error("X-Request-ID header not set")
 38→	}
 39→}
