 41→func TestRequestID_PassesThrough(t *testing.T) {
 42→	handler := RequestID(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
 43→		id := requestIDFromContext(r.Context())
 44→		if id != "my-custom-id" {
 45→			t.Errorf("request ID = %q, want %q", id, "my-custom-id")
 46→		}
 47→		w.WriteHeader(http.StatusOK)
 48→	}))
 49→
 50→	req := httptest.NewRequest("GET", "/", nil)
 51→	req.Header.Set("X-Request-ID", "my-custom-id")
 52→
 53→	rr := httptest.NewRecorder()
 54→	handler.ServeHTTP(rr, req)
 55→
 56→	if got := rr.Header().Get("X-Request-ID"); got != "my-custom-id" {
 57→		t.Errorf("X-Request-ID = %q, want %q", got, "my-custom-id")
 58→	}
