 39→func TestPageFetchWorker_Success(t *testing.T) {
 40→	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
 41→		w.Header().Set("Content-Type", "text/html")
 42→		_, _ = w.Write([]byte(testHTML))
 43→	}))
 44→	defer srv.Close()
 45→
 46→	items := &mockItemService{}
 47→	w := &PageFetchWorker{
 48→		Items:  items,
 49→		Client: srv.Client(),
 50→	}
 51→
 52→	job := &river.Job[PageFetchArgs]{
 53→		Args: PageFetchArgs{
 54→			ItemID: uuid.New(),
 55→			URL:    srv.URL,
 56→		},
 57→	}
 58→
 59→	err := w.Work(context.Background(), job)
 60→	if err != nil {
 61→		t.Fatalf("Work() returned error: %v", err)
 62→	}
 63→
 64→	// Should have called UpdateContent twice: processing + ready
 65→	if len(items.updates) != 2 {
 66→		t.Fatalf("expected 2 UpdateContent calls, got %d", len(items.updates))
 67→	}
 68→
 69→	if items.updates[0].Status != "processing" {
 70→		t.Errorf("first update status = %q, want %q", items.updates[0].Status, "processing")
 71→	}
 72→
 73→	final := items.updates[1]
 74→	if final.Status != "ready" {
 75→		t.Errorf("final status = %q, want %q", final.Status, "ready")
 76→	}
 77→	if final.Title == nil || *final.Title == "" {
 78→		t.Error("expected non-empty title in final update")
 79→	}
 80→	if final.ContentText == nil || *final.ContentText == "" {
 81→		t.Error("expected non-empty content_text in final update")
 82→	}
 83→}
