  1→package worker
  2→
  3→import (
  4→	"context"
  5→	"fmt"
  6→	"log/slog"
  7→	"net/http"
  8→	"strings"
  9→	"time"
 10→
 11→	readability "github.com/go-shiori/go-readability"
 12→	"github.com/google/uuid"
 13→	"github.com/jackc/pgx/v5"
 14→	"github.com/riverqueue/river"
 15→
 16→	"github.com/ketang/flotsam/api/internal/item"
 17→	"github.com/ketang/flotsam/api/internal/storage"
 18→)
 19→
 20→// ItemContentUpdater updates worker-managed fields on items.
 21→type ItemContentUpdater interface {
 22→	UpdateContent(ctx context.Context, itemID uuid.UUID, input item.ContentUpdate) error
 23→}
 24→
 25→const (
 26→	fetchTimeout = 30 * time.Second
 27→	userAgent    = "Flotsam/1.0 (bookmark fetcher)"
 28→)
 29→
 30→// PageFetchArgs are the arguments for a page fetch job.
 31→type PageFetchArgs struct {
 32→	ItemID uuid.UUID `json:"item_id"`
 33→	URL    string    `json:"url"`
 34→}
 35→
 36→func (PageFetchArgs) Kind() string { return "page_fetch" }
 37→
 38→// PageFetchWorker fetches and extracts readable content from bookmark URLs.
 39→type PageFetchWorker struct {
 40→	river.WorkerDefaults[PageFetchArgs]
 41→	Items       ItemContentUpdater
 42→	Storage     *storage.Client        // nil if S3 not configured
 43→	Client      *http.Client           // nil uses a default client with timeout
 44→	RiverClient *river.Client[pgx.Tx]  // for enqueuing follow-up jobs (embed)
 45→}
 46→
 47→func (w *PageFetchWorker) httpClient() *http.Client {
 48→	if w.Client != nil {
 49→		return w.Client
 50→	}
 51→	return &http.Client{Timeout: fetchTimeout}
 52→}
 53→
 54→func (w *PageFetchWorker) Work(ctx context.Context, job *river.Job[PageFetchArgs]) error {
 55→	itemID := job.Args.ItemID
 56→	url := job.Args.URL
 57→
 58→	slog.InfoContext(ctx, "worker: page_fetch: processing",
 59→		"item_id", itemID,
 60→		"url", url,
 61→	)
 62→
 63→	// Mark item as processing
 64→	if err := w.Items.UpdateContent(ctx, itemID, item.ContentUpdate{Status: "processing"}); err != nil {
 65→		return fmt.Errorf("worker: page_fetch: set processing: %w", err)
 66→	}
 67→
 68→	// Fetch and extract content
 69→	article, err := w.fetchAndExtract(ctx, url)
 70→	if err != nil {
 71→		// Set item to error status
 72→		_ = w.Items.UpdateContent(ctx, itemID, item.ContentUpdate{Status: "error"})
 73→		return fmt.Errorf("worker: page_fetch: fetch: %w", err)
 74→	}
 75→
 76→	// Upload HTML to S3 if storage is configured
 77→	var contentURL *string
 78→	if w.Storage != nil && article.Content != "" {
 79→		key := fmt.Sprintf("items/%s/page.html", itemID)
 80→		if err := w.Storage.Upload(ctx, key, strings.NewReader(article.Content), "text/html"); err != nil {
 81→			slog.ErrorContext(ctx, "worker: page_fetch: s3 upload failed, continuing without",
 82→				"item_id", itemID,
 83→				"error", err,
 84→			)
 85→		} else {
 86→			contentURL = &key
 87→		}
 88→	}
 89→
 90→	// Build content update
 91→	update := item.ContentUpdate{Status: "ready"}
 92→	if article.Title != "" {
 93→		update.Title = &article.Title
 94→	}
 95→	if article.TextContent != "" {
 96→		update.ContentText = &article.TextContent
 97→	}
 98→	if contentURL != nil {
 99→		update.ContentURL = contentURL
100→	}
101→
102→	if err := w.Items.UpdateContent(ctx, itemID, update); err != nil {
103→		return fmt.Errorf("worker: page_fetch: update item: %w", err)
104→	}
105→
106→	slog.InfoContext(ctx, "worker: page_fetch: done",
107→		"item_id", itemID,
108→		"title", article.Title,
109→		"text_length", len(article.TextContent),
110→	)
111→
112→	// Enqueue embedding job if content was extracted
113→	if article.TextContent != "" {
114→		w.enqueueEmbed(ctx, itemID, article.TextContent)
115→	}
116→
117→	return nil
118→}
119→
120→type fetchResult struct {
121→	Title       string
122→	TextContent string
123→	Content     string // HTML content
124→}
125→
126→func (w *PageFetchWorker) fetchAndExtract(ctx context.Context, url string) (*fetchResult, error) {
127→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
128→	if err != nil {
129→		return nil, fmt.Errorf("build request: %w", err)
130→	}
131→	req.Header.Set("User-Agent", userAgent)
132→
133→	resp, err := w.httpClient().Do(req)
134→	if err != nil {
135→		return nil, fmt.Errorf("http get: %w", err)
136→	}
137→	defer func() { _ = resp.Body.Close() }()
138→
139→	if resp.StatusCode >= 400 {
140→		return nil, fmt.Errorf("http status %d for %s", resp.StatusCode, url)
141→	}
142→
143→	article, err := readability.FromReader(resp.Body, nil)
144→	if err != nil {
145→		return nil, fmt.Errorf("readability parse: %w", err)
146→	}
147→
148→	return &fetchResult{
149→		Title:       article.Title,
150→		TextContent: article.TextContent,
151→		Content:     article.Content,
152→	}, nil
153→}
154→
155→func (w *PageFetchWorker) enqueueEmbed(ctx context.Context, itemID uuid.UUID, content string) {
156→	if w.RiverClient == nil {
157→		return
158→	}
159→	_, err := w.RiverClient.Insert(ctx, &EmbedArgs{
160→		ItemID:  itemID,
161→		Content: content,
162→	}, nil)
163→	if err != nil {
164→		slog.ErrorContext(ctx, "worker: page_fetch: failed to enqueue embed job",
165→			"item_id", itemID,
166→			"error", err,
167→		)
168→	}
169→}
